1	/**
2	 * The Clerk — writ lifecycle management apparatus.
3	 *
4	 * The Clerk manages the lifecycle of writs: lightweight work orders that flow
5	 * through a fixed status machine (ready → active → completed/failed, or
6	 * ready/active → cancelled). Each writ has a type, a title, a body, and
7	 * optional codex and resolution fields.
8	 *
9	 * Writ types are validated against the guild config's writTypes field plus the
10	 * built-in type ('mandate'). An unknown type is rejected at post time.
11	 *
12	 * See: docs/architecture/apparatus/clerk.md
13	 */
14	
15	import type { Plugin, StartupContext } from '@shardworks/nexus-core';
16	import { guild, generateId } from '@shardworks/nexus-core';
17	import type { StacksApi, Book, WhereClause } from '@shardworks/stacks-apparatus';
18	
19	import type {
20	  ClerkApi,
21	  ClerkConfig,
22	  WritDoc,
23	  WritLinkDoc,
24	  WritLinks,
25	  WritStatus,
26	  PostCommissionRequest,
27	  WritFilters,
28	} from './types.ts';
29	
30	import {
31	  commissionPost,
32	  writShow,
33	  writList,
34	  writAccept,
35	  writComplete,
36	  writFail,
37	  writCancel,
38	  writLink,
39	  writUnlink,
40	} from './tools/index.ts';
41	
42	// ── Built-in writ types ──────────────────────────────────────────────
43	
44	const BUILTIN_TYPES = new Set(['mandate']);
45	
46	// ── Status machine ───────────────────────────────────────────────────
47	
48	const ALLOWED_FROM: Record<WritStatus, WritStatus[]> = {
49	  active: ['ready'],
50	  completed: ['active'],
51	  failed: ['active'],
52	  cancelled: ['ready', 'active'],
53	  ready: [],
54	};
55	
56	const TERMINAL_STATUSES = new Set<WritStatus>(['completed', 'failed', 'cancelled']);
57	
58	// ── Factory ──────────────────────────────────────────────────────────
59	
60	export function createClerk(): Plugin {
61	  let writs: Book<WritDoc>;
62	  let links: Book<WritLinkDoc>;
63	
64	  // ── Helpers ──────────────────────────────────────────────────────
65	
66	  function resolveClerkConfig(): ClerkConfig {
67	    return guild().guildConfig().clerk ?? {};
68	  }
69	
70	  function resolveWritTypes(): Set<string> {
71	    const config = resolveClerkConfig();
72	    const declared = (config.writTypes ?? []).map((entry) => entry.name);
73	    return new Set([...BUILTIN_TYPES, ...declared]);
74	  }
75	
76	  function resolveDefaultType(): string {
77	    const config = resolveClerkConfig();
78	    return config.defaultType ?? 'mandate';
79	  }
80	
81	  function buildWhereClause(filters?: WritFilters): WhereClause | undefined {
82	    const conditions: WhereClause = [];
83	    if (filters?.status) {
84	      conditions.push(['status', '=', filters.status]);
85	    }
86	    if (filters?.type) {
87	      conditions.push(['type', '=', filters.type]);
88	    }
89	    return conditions.length > 0 ? conditions : undefined;
90	  }
91	
92	  // ── API ──────────────────────────────────────────────────────────
93	
94	  const api: ClerkApi = {
95	    async post(request: PostCommissionRequest): Promise<WritDoc> {
96	      const type = request.type ?? resolveDefaultType();
97	      const validTypes = resolveWritTypes();
98	
99	      if (!validTypes.has(type)) {
100	        throw new Error(
101	          `Unknown writ type "${type}". Declared types: ${[...validTypes].join(', ')}.`,
102	        );
103	      }
104	
105	      const now = new Date().toISOString();
106	      const writ: WritDoc = {
107	        id: generateId('w', 6),
108	        type,
109	        status: 'ready',
110	        title: request.title,
111	        body: request.body,
112	        ...(request.codex !== undefined ? { codex: request.codex } : {}),
113	        createdAt: now,
114	        updatedAt: now,
115	      };
116	
117	      await writs.put(writ);
118	      return writ;
119	    },
120	
121	    async show(id: string): Promise<WritDoc> {
122	      const writ = await writs.get(id);
123	      if (!writ) {
124	        throw new Error(`Writ "${id}" not found.`);
125	      }
126	      return writ;
127	    },
128	
129	    async list(filters?: WritFilters): Promise<WritDoc[]> {
130	      const where = buildWhereClause(filters);
131	      const limit = filters?.limit ?? 20;
132	      const offset = filters?.offset;
133	
134	      return writs.find({
135	        where,
136	        orderBy: ['createdAt', 'desc'],
137	        limit,
138	        ...(offset !== undefined ? { offset } : {}),
139	      });
140	    },
141	
142	    async count(filters?: WritFilters): Promise<number> {
143	      const where = buildWhereClause(filters);
144	      return writs.count(where);
145	    },
146	
147	    async link(sourceId: string, targetId: string, type: string): Promise<WritLinkDoc> {
148	      if (sourceId === targetId) {
149	        throw new Error(`Cannot link a writ to itself: "${sourceId}".`);
150	      }
151	      if (!type || !type.trim()) {
152	        throw new Error('Link type must be a non-empty string.');
153	      }
154	
155	      const source = await writs.get(sourceId);
156	      if (!source) {
157	        throw new Error(`Writ "${sourceId}" not found.`);
158	      }
159	      const target = await writs.get(targetId);
160	      if (!target) {
161	        throw new Error(`Writ "${targetId}" not found.`);
162	      }
163	
164	      const id = `${sourceId}:${targetId}:${type}`;
165	      const existing = await links.get(id);
166	      if (existing) {
167	        return existing;
168	      }
169	
170	      const doc: WritLinkDoc = {
171	        id,
172	        sourceId,
173	        targetId,
174	        type,
175	        createdAt: new Date().toISOString(),
176	      };
177	      await links.put(doc);
178	      return doc;
179	    },
180	
181	    async links(writId: string): Promise<WritLinks> {
182	      const [outbound, inbound] = await Promise.all([
183	        links.find({ where: [['sourceId', '=', writId]] }),
184	        links.find({ where: [['targetId', '=', writId]] }),
185	      ]);
186	      return { outbound, inbound };
187	    },
188	
189	    async unlink(sourceId: string, targetId: string, type: string): Promise<void> {
190	      const id = `${sourceId}:${targetId}:${type}`;
191	      await links.delete(id);
192	    },
193	
194	    async transition(id: string, to: WritStatus, fields?: Partial<WritDoc>): Promise<WritDoc> {
195	      const writ = await writs.get(id);
196	      if (!writ) {
197	        throw new Error(`Writ "${id}" not found.`);
198	      }
199	
200	      const allowedFrom = ALLOWED_FROM[to];
201	      if (!allowedFrom.includes(writ.status)) {
202	        throw new Error(
203	          `Cannot transition writ "${id}" to "${to}": status is "${writ.status}", expected one of: ${allowedFrom.join(', ')}.`,
204	        );
205	      }
206	
207	      const now = new Date().toISOString();
208	      const isTerminal = TERMINAL_STATUSES.has(to);
209	
210	      // Strip managed fields — callers cannot override id, status, or timestamps
211	      // controlled by the status machine.
212	      const { id: _id, status: _status, createdAt: _c, updatedAt: _u,
213	        acceptedAt: _a, resolvedAt: _r, ...safeFields } = (fields ?? {}) as WritDoc;
214	
215	      const patch: Partial<Omit<WritDoc, 'id'>> = {
216	        status: to,
217	        updatedAt: now,
218	        ...(to === 'active' ? { acceptedAt: now } : {}),
219	        ...(isTerminal ? { resolvedAt: now } : {}),
220	        ...safeFields,
221	      };
222	
223	      return writs.patch(id, patch);
224	    },
225	  };
226	
227	  // ── Apparatus ────────────────────────────────────────────────────
228	
229	  return {
230	    apparatus: {
231	      requires: ['stacks'],
232	
233	      supportKit: {
234	        books: {
235	          writs: {
236	            indexes: ['status', 'type', 'createdAt', ['status', 'type'], ['status', 'createdAt']],
237	          },
238	          links: {
239	            indexes: ['sourceId', 'targetId', 'type', ['sourceId', 'type'], ['targetId', 'type']],
240	          },
241	        },
242	        tools: [
243	          commissionPost,
244	          writShow,
245	          writList,
246	          writAccept,
247	          writComplete,
248	          writFail,
249	          writCancel,
250	          writLink,
251	          writUnlink,
252	        ],
253	      },
254	
255	      provides: api,
256	
257	      start(_ctx: StartupContext): void {
258	        const stacks = guild().apparatus<StacksApi>('stacks');
259	        writs = stacks.book<WritDoc>('clerk', 'writs');
260	        links = stacks.book<WritLinkDoc>('clerk', 'links');
261	      },
262	    },
263	  };
264	}
