324	// ── Block type type guard ──────────────────────────────────────────────
325	
326	function isBlockType(value: unknown): value is BlockType {
327	  return (
328	    typeof value === 'object' &&
329	    value !== null &&
330	    typeof (value as Record<string, unknown>).id === 'string' &&
331	    typeof (value as Record<string, unknown>).check === 'function'
332	  );
333	}
334	
335	// ── Block type registry ────────────────────────────────────────────────
336	
337	class BlockTypeRegistry {
338	  private readonly types = new Map<string, BlockType>();
339	
340	  register(plugin: LoadedPlugin): void {
341	    if (isLoadedKit(plugin)) {
342	      this.registerFromKit(plugin.kit);
343	    } else if (isLoadedApparatus(plugin)) {
344	      if (plugin.apparatus.supportKit) {
345	        this.registerFromKit(plugin.apparatus.supportKit);
346	      }
347	    }
348	  }
349	
350	  private registerFromKit(kit: Record<string, unknown>): void {
351	    const raw = kit.blockTypes;
352	    if (typeof raw !== 'object' || raw === null) return;
353	    for (const value of Object.values(raw as Record<string, unknown>)) {
354	      if (isBlockType(value)) {
355	        this.types.set(value.id, value);
356	      }
357	    }
358	  }
359	
360	  get(id: string): BlockType | undefined {
361	    return this.types.get(id);
362	  }
363	}
