365	// ── Apparatus factory ──────────────────────────────────────────────────
366	
367	export function createSpider(): Plugin {
368	  let rigsBook: Book<RigDoc>;
369	  let sessionsBook: ReadOnlyBook<SessionDoc>;
370	  let writsBook: ReadOnlyBook<WritDoc>;
371	  let clerk: ClerkApi;
372	  let fabricator: FabricatorApi;
373	  let spiderConfig: SpiderConfig = {};
374	
375	  const blockTypeRegistry = new BlockTypeRegistry();
376	
377	  /**
378	   * In-memory store for block records that have been cleared.
379	   * Key: "rigId:engineId". Written when an engine is unblocked (via checker or resume()).
380	   * Read and deleted in tryRun() when building EngineRunContext.
381	   */
382	  const pendingPriorBlocks = new Map<string, BlockRecord>();
383	
384	  // ── Internal crawl operations ─────────────────────────────────────
385	
386	  /**
387	   * Mark an engine failed and propagate failure to the rig (same update).
388	   * Cancels all pending and blocked engines.
389	   */
390	  async function failEngine(
391	    rig: RigDoc,
392	    engineId: string,
393	    errorMessage: string,
394	  ): Promise<void> {
395	    const now = new Date().toISOString();
396	    const updatedEngines = rig.engines.map((e) => {
397	      if (e.id === engineId) {
398	        return { ...e, status: 'failed' as const, error: errorMessage, completedAt: now };
399	      }
400	      if (e.status === 'pending' || e.status === 'blocked') {
401	        return { ...e, status: 'cancelled' as const, block: undefined };
402	      }
403	      return e;
404	    });
405	    await rigsBook.patch(rig.id, {
406	      engines: updatedEngines,
407	      status: 'failed',
408	    });
409	  }
410	
411	  /**
412	   * Phase 1 — collect.
413	   *
414	   * Find the first running engine with a sessionId whose session has
415	   * reached a terminal state. Populate yields and advance the engine
416	   * (and possibly the rig) to completed or failed.
417	   *
418	   * After collecting a completed engine, check whether the rig has
419	   * become blocked (no running engines, no runnable engines, some blocked).
420	   */
421	  async function tryCollect(): Promise<CrawlResult | null> {
422	    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
423	    for (const rig of runningRigs) {
424	      for (const engine of rig.engines) {
425	        if (engine.status !== 'running' || !engine.sessionId) continue;
426	
427	        const session = await sessionsBook.get(engine.sessionId);
428	        if (!session || session.status === 'running') continue;
429	
430	        // Terminal session found — collect.
431	        const now = new Date().toISOString();
432	
433	        if (session.status === 'failed' || session.status === 'timeout') {
434	          await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
435	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
436	        }
437	
438	        // Completed session — assemble yields via engine's collect() or generic default.
439	        const design = fabricator.getEngineDesign(engine.designId);
440	        let yields: unknown;
441	        if (design?.collect) {
442	          const givens = { ...engine.givensSpec };
443	          const upstream = buildUpstreamMap(rig);
444	          const context = { rigId: rig.id, engineId: engine.id, upstream };
445	          yields = await design.collect(engine.sessionId!, givens, context);
446	        } else {
447	          yields = {
448	            sessionId: session.id,
449	            sessionStatus: session.status,
450	            ...(session.output !== undefined ? { output: session.output } : {}),
451	          };
452	        }
453	
454	        if (!isJsonSerializable(yields)) {
455	          await failEngine(rig, engine.id, 'Session yields are not JSON-serializable');
456	          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
457	        }
458	
459	        const updatedEngines = rig.engines.map((e) =>
